   217→#include <stdio.h>
   218→#include <ac/stdlib.h>
   219→
   220→#include <ac/errno.h>
   221→#include <ac/unistd.h>
   222→
   223→#ifdef HAVE_SYS_FILE_H
   224→#include <sys/file.h>
   225→#endif
   226→
   227→#ifdef HAVE_IO_H
   228→#include <io.h>
   229→#endif
   230→
   231→#ifdef HAVE_FCNTL_H
   232→#include <fcntl.h>
   233→#endif
