   856→static int hash_crypt(
   857→	const struct berval *scheme,
   858→	const struct berval *passwd,
   859→	struct berval *hash,
   860→	const char **text )
   861→{
   862→	unsigned char salt[32];	/* salt suitable for most anything */
   863→	unsigned int i;
   864→	char *save;
   865→	int rc;
   866→
   867→	for( i=0; i<passwd->bv_len; i++) {
